      strictEqual(clamp(5, 0, 10), 5);
    });

    it("clamps to the lower bound", () => {
      strictEqual(clamp(-3, 0, 10), 0);
    });

    it("clamps to the upper bound", () => {
      strictEqual(clamp(15, 0, 10), 10);
    });
  });

  describe("round", () => {
    it("rounds to integer by default", () => {
      strictEqual(round(2.5), 3);
    });

    it("rounds to the specified decimal places", () => {
