    });

    it("rounds negative numbers correctly", () => {
      strictEqual(round(-1.005, 2), -1);
    });
  });

  describe("inRange", () => {
    it("returns true when value is inside the range", () => {
      strictEqual(inRange(5, 1, 10), true);
    });

    it("returns true at the boundaries (inclusive)", () => {
      strictEqual(inRange(1, 1, 10), true);
      strictEqual(inRange(10, 1, 10), true);
    });

    it("returns false when value is outside the range", () => {
      strictEqual(inRange(0, 1, 10), false);
      strictEqual(inRange(11, 1, 10), false);
    });
  });
});

import { describe, it } from "node:test";
import { deepStrictEqual, strictEqual } from "node:assert/strict";
import { pick, omit, isEmpty } from "../src/objects.js";

describe("objects", () => {
  describe("pick", () => {
    it("returns an object with only the specified keys", () => {
      deepStrictEqual(pick({ a: 1, b: 2, c: 3 }, ["a", "c"]), { a: 1, c: 3 });
    });

    it("ignores keys that do not exist in the source", () => {
      deepStrictEqual(pick({ x: 1 }, ["y"]), {});
    });

    it("returns empty object when keys array is empty", () => {
      deepStrictEqual(pick({ a: 1, b: 2 }, []), {});
    });
  });

  describe("omit", () => {
    it("returns an object without the omitted keys", () => {
      deepStrictEqual(omit({ a: 1, b: 2, c: 3 }, ["b"]), { a: 1, c: 3 });
    });

    it("returns a full copy when keys array is empty", () => {
      deepStrictEqual(omit({ a: 1 }, []), { a: 1 });
    });
  });

  describe("isEmpty", () => {
    it("returns true for null", () => {
      strictEqual(isEmpty(null), true);
    });

    it("returns true for an empty object", () => {
      strictEqual(isEmpty({}), true);
    });

    it("returns false for an object with keys", () => {
      strictEqual(isEmpty({ a: 1 }), false);
    });
  });
});

import { describe, it } from "node:test";
import { strictEqual } from "node:assert/strict";
import { formatISO, addDays, diffDays } from "../src/dates.js";

describe("dates", () => {
  describe("formatISO", () => {
    it("formats a date string as ISO 8601", () => {
      strictEqual(formatISO("2024-06-01"), "2024-06-01T00:00:00.000Z");
    });

    it("formats a Date instance", () => {
      strictEqual(
        formatISO(new Date("2024-01-15")),
        "2024-01-15T00:00:00.000Z",
      );
    });
  });

  describe("addDays", () => {
    it("adds positive days", () => {
      const result = addDays("2024-01-01", 5);
      strictEqual(result.toISOString(), "2024-01-06T00:00:00.000Z");
    });

    it("subtracts days with a negative value", () => {
      const result = addDays("2024-01-10", -3);
      strictEqual(result.toISOString(), "2024-01-07T00:00:00.000Z");
    });

    it("returns a Date instance", () => {
      strictEqual(addDays("2024-01-01", 0) instanceof Date, true);
    });
  });

  describe("diffDays", () => {
    it("returns positive difference when b is after a", () => {
      strictEqual(diffDays("2024-01-01", "2024-01-11"), 10);
    });

    it("returns negative difference when a is after b", () => {
      strictEqual(diffDays("2024-01-11", "2024-01-01"), -10);
    });

    it("returns 0 for the same date", () => {
      strictEqual(diffDays("2024-03-15", "2024-03-15"), 0);
    });
  });
});

