 * @param {*} input - The value to slugify. Will be coerced to a string.
 * @returns {string} A lowercase, hyphen-separated slug with no leading/trailing hyphens.
 * @example
 * slugify('Hello World!') // 'hello-world'
 * slugify('  Foo -- Bar  ') // 'foo-bar'
 */
export function slugify(input) {
  return String(input)
    .toLowerCase()
    .trim()
    .replace(/[^a-z0-9]+/g, "-")
    .replace(/^-+|-+$/g, "");
}

/**
